#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void dfs(char* num, int target, int start, long long current_value, long long last_operand, char* expression, char*** result, int* returnSize) {
    if (start == strlen(num)) {
        if (current_value == target) {
            (*returnSize)++;
            (*result) = realloc((*result), (*returnSize) * sizeof(char*));
            (*result)[(*returnSize) - 1] = strdup(expression);
        }
        return;
    }
    for (int i = start; i < strlen(num); i++) {
        if (i > start && num[start] == '0') return;
        char current_num[10];
        strncpy(current_num, num + start, i - start + 1);
        current_num[i - start + 1] = '\0';
        long long current_num_val = atoll(current_num);
        if (start == 0) {
            char new_expression[100];
            sprintf(new_expression, "%s", current_num);
            dfs(num, target, i + 1, current_num_val, current_num_val, new_expression, result, returnSize);
        } else {
            char new_expression[100];
            sprintf(new_expression, "%s+%s", expression, current_num);
            dfs(num, target, i + 1, current_value + current_num_val, current_num_val, new_expression, result, returnSize);
            sprintf(new_expression, "%s-%s", expression, current_num);
            dfs(num, target, i + 1, current_value - current_num_val, -current_num_val, new_expression, result, returnSize);
            sprintf(new_expression, "%s*%s", expression, current_num);
            dfs(num, target, i + 1, current_value - last_operand + last_operand * current_num_val, last_operand * current_num_val, new_expression, result, returnSize);
        }
    }
}

char** addOperators(char* num, int target, int* returnSize) {
    char*** result = malloc(sizeof(char**));
    *returnSize = 0;
    dfs(num, target, 0, 0, 0, "", result, returnSize);
    return *result;
}

